import React, { useState, useEffect, useRef } from 'react';
import { Link } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import Navbar from '../components/Navbar';

const API = '';

const nama = 'Hagia Sofiana';
const tentang =
  'Full Stack Developer specializing in modern web and mobile development. Proficient in PHP, Laravel, JavaScript, React, Python, Java, and MySQL, with a passion for building scalable applications, writing clean code, and continuously exploring new technologies.';
const skills = ['HTML', 'CSS', 'JavaScript', 'PHP', 'MySQL', 'Python', 'Bootstrap', 'Java', 'React', 'Vite'];

const roles = [
  'Software Engineer',
  'Full Stack',
  'Web Development',
  'Mobile Development',
  'Desktop Development'
];

const floatingLabels = [
  'Software Engineer', 'Full Stack Developer', 'Frontend Developer', 
  'Backend Developer', 'React.js', 'Node.js', 'Express.js', 
  'JavaScript', 'PHP', 'Laravel', 'MySQL', 'Git',
  'REST API', 'Responsive Design', 'Clean Code', 'API Integration',
  'Problem Solving'
];

const techStack = [
  { name: 'React', icon: 'fa-react' },
  { name: 'Node.js', icon: 'fa-node-js' },
  { name: 'Express', icon: 'fa-express' },
  { name: 'JavaScript', icon: 'fa-js-square' },
  { name: 'PHP', icon: 'fa-php' },
  { name: 'Laravel', icon: 'fa-laravel' },
  { name: 'MySQL', icon: 'fa-database' },
  { name: 'Git', icon: 'fa-git-alt' },
  { name: 'GitHub', icon: 'fa-github' },
  { name: 'Bootstrap', icon: 'fa-bootstrap' },
  { name: 'Tailwind CSS', icon: 'fa-tailwind' },
  { name: 'VS Code', icon: 'fa-code' },
  { name: 'Figma', icon: 'fa-figma' },
  { name: 'Postman', icon: 'fa-postman' }
];

export default function Home() {
  const [recentProjects, setRecentProjects] = useState([]);
  const [totalProject, setTotalProject] = useState(0);
  const [isLoaded, setIsLoaded] = useState(false);
  const [roleIndex, setRoleIndex] = useState(0);
  const [cursorPosition, setCursorPosition] = useState({ x: 0, y: 0 });
  const [hoveredCard, setHoveredCard] = useState(null);
  const containerRef = useRef(null);

  useEffect(() => {
    window.scrollTo(0, 0);
  }, []);

  useEffect(() => {
    fetch(`${API}/api/projects/recent`)
      .then((r) => r.json())
      .then(setRecentProjects)
      .catch(console.error);

    fetch(`${API}/api/projects/count`)
      .then((r) => r.json())
      .then((d) => setTotalProject(d.total))
      .catch(console.error);
  }, []);

  useEffect(() => {
    const interval = setInterval(() => {
      setRoleIndex((prev) => (prev + 1) % roles.length);
    }, 3000);
    return () => clearInterval(interval);
  }, []);

  useEffect(() => {
    const timer = setTimeout(() => {
      setIsLoaded(true);
    }, 100);
    return () => clearTimeout(timer);
  }, []);

  useEffect(() => {
    const handleMouseMove = (e) => {
      setCursorPosition({ x: e.clientX, y: e.clientY });
    };
    window.addEventListener('mousemove', handleMouseMove);
    return () => window.removeEventListener('mousemove', handleMouseMove);
  }, []);

  const fadeInVariants = {
    hidden: { opacity: 0, y: 30 },
    visible: (i) => ({
      opacity: 1,
      y: 0,
      transition: { delay: i * 0.1, duration: 0.8, ease: [0.34, 1.56, 0.64, 1] }
    })
  };

  const marqueeItems = [...techStack, ...techStack, ...techStack];

  return (
    <>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Space+Grotesk:wght@300;400;500;600;700;800;900&family=Inter:wght@300;400;500;600;700&family=IBM+Plex+Mono:wght@400;500;600;700&display=swap');

        :root {
          --bg-primary: #090909;
          --bg-secondary: #141414;
          --accent-pink: #FF3EA5;
          --accent-secondary: #FF7CC7;
          --rose-gold: #D8A7B1;
          --text-primary: #F5F5F5;
          --text-secondary: #9B9B9B;
          --card-bg: rgba(255,255,255,.03);
          --border-color: rgba(255,255,255,.08);
          --glass-bg: rgba(255,255,255,.02);
        }

        * { margin: 0; padding: 0; box-sizing: border-box; }

        body {
          background: var(--bg-primary);
          color: var(--text-primary);
          min-height: 100vh;
          font-family: 'Inter', sans-serif;
          overflow-x: hidden;
          cursor: none;
        }

        /* Custom Cursor */
        .cursor-glow {
          position: fixed;
          width: 300px;
          height: 300px;
          border-radius: 50%;
          background: radial-gradient(circle, rgba(255,62,165,0.06) 0%, transparent 70%);
          pointer-events: none;
          z-index: 9999;
          transform: translate(-50%, -50%);
          transition: all 0.1s ease;
        }

        .cursor-dot {
          position: fixed;
          width: 6px;
          height: 6px;
          border-radius: 50%;
          background: var(--accent-pink);
          pointer-events: none;
          z-index: 9999;
          transform: translate(-50%, -50%);
          transition: all 0.08s ease;
        }

        /* Background with Leopard Texture */
        .bg-layer {
          position: fixed;
          inset: 0;
          z-index: 0;
          pointer-events: none;
          background: 
            radial-gradient(ellipse at 30% 20%, rgba(255,62,165,0.06) 0%, transparent 50%),
            radial-gradient(ellipse at 70% 80%, rgba(255,62,165,0.04) 0%, transparent 50%),
            radial-gradient(ellipse at 50% 50%, rgba(255,124,199,0.02) 0%, transparent 70%);
        }

        .bg-layer::before {
          content: '';
          position: absolute;
          inset: 0;
          background-image: 
            radial-gradient(ellipse at 20% 30%, rgba(255,62,165,0.02) 0%, transparent 4px),
            radial-gradient(ellipse at 80% 70%, rgba(255,62,165,0.015) 0%, transparent 3px),
            radial-gradient(ellipse at 40% 60%, rgba(255,62,165,0.01) 0%, transparent 2px);
          background-size: 120px 120px, 180px 180px, 200px 200px;
          opacity: 0.6;
        }

        .bg-layer::after {
          content: '';
          position: absolute;
          inset: 0;
          background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 256 256' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noise'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noise)' opacity='0.03'/%3E%3C/svg%3E");
          opacity: 0.3;
          mix-blend-mode: overlay;
        }

        .main-content {
          position: relative;
          z-index: 1;
          padding-top: 120px;
        }

        /* Floating Labels Animation */
        @keyframes floatLabel {
          0%, 100% { transform: translate(0, 0) rotate(0deg) scale(1); }
          25% { transform: translate(15px, -20px) rotate(2deg) scale(1.05); }
          50% { transform: translate(-10px, 15px) rotate(-1deg) scale(0.95); }
          75% { transform: translate(20px, 10px) rotate(1deg) scale(1.02); }
        }

        .floating-label {
          position: absolute;
          padding: 8px 18px;
          border-radius: 50px;
          background: var(--card-bg);
          border: 1px solid var(--border-color);
          color: var(--text-secondary);
          font-size: 0.75rem;
          font-weight: 500;
          font-family: 'Inter', sans-serif;
          backdrop-filter: blur(10px);
          pointer-events: none;
          white-space: nowrap;
          animation: floatLabel 8s ease-in-out infinite;
          transition: all 0.3s ease;
        }

        .floating-label:hover {
          color: var(--text-primary);
          border-color: var(--accent-pink);
        }

        /* Hero Section */
        .hero-container {
          min-height: 80vh;
          display: flex;
          align-items: center;
          padding: 2rem 0;
        }

        .hero-content {
          position: relative;
          z-index: 2;
        }

        .hero-badge {
          display: inline-flex;
          align-items: center;
          gap: 0.5rem;
          background: var(--card-bg);
          border: 1px solid var(--border-color);
          border-radius: 50px;
          padding: 0.4rem 1.2rem;
          font-size: 0.8rem;
          color: var(--text-secondary);
          margin-bottom: 1.5rem;
          font-weight: 500;
        }

        .hero-badge .badge-dot {
          width: 6px;
          height: 6px;
          border-radius: 50%;
          background: #4ADE80;
          animation: pulse 2s infinite;
        }

        @keyframes pulse {
          0%, 100% { opacity: 1; transform: scale(1); }
          50% { opacity: 0.5; transform: scale(0.8); }
        }

        .hero-title {
          font-family: 'Space Grotesk', sans-serif;
          font-size: 4.5rem;
          font-weight: 900;
          line-height: 1.05;
          margin-bottom: 1.5rem;
          letter-spacing: -2px;
        }

        .hero-title .name-highlight {
          background: linear-gradient(135deg, var(--accent-pink), var(--accent-secondary), var(--rose-gold));
          -webkit-background-clip: text;
          -webkit-text-fill-color: transparent;
          background-clip: text;
        }

        .hero-title .role-text {
          background: linear-gradient(135deg, var(--text-primary), var(--text-secondary));
          -webkit-background-clip: text;
          -webkit-text-fill-color: transparent;
          background-clip: text;
          display: inline-block;
        }

        .hero-subtitle {
          font-size: 1.1rem;
          color: var(--text-secondary);
          max-width: 480px;
          line-height: 1.8;
          margin-bottom: 2.5rem;
          font-weight: 400;
        }

        .hero-actions {
          display: flex;
          gap: 1rem;
          flex-wrap: wrap;
          margin-bottom: 2.5rem;
        }

        .btn-primary {
          display: inline-flex;
          align-items: center;
          gap: 0.75rem;
          padding: 0.8rem 2.5rem;
          border-radius: 50px;
          background: var(--accent-pink);
          color: var(--bg-primary);
          font-weight: 600;
          font-size: 0.9rem;
          text-decoration: none;
          transition: all 0.3s cubic-bezier(0.34, 1.56, 0.64, 1);
          border: none;
          cursor: pointer;
          position: relative;
          overflow: hidden;
        }

        .btn-primary::before {
          content: '';
          position: absolute;
          inset: 0;
          background: linear-gradient(135deg, var(--accent-pink), var(--accent-secondary));
          opacity: 0;
          transition: opacity 0.3s ease;
        }

        .btn-primary:hover {
          transform: translateY(-3px) scale(1.03);
          box-shadow: 0 20px 60px rgba(255,62,165,0.3);
        }

        .btn-primary:hover::before {
          opacity: 1;
        }

        .btn-primary span {
          position: relative;
          z-index: 1;
        }

        .btn-secondary {
          display: inline-flex;
          align-items: center;
          gap: 0.75rem;
          padding: 0.8rem 2.5rem;
          border-radius: 50px;
          background: var(--card-bg);
          border: 1px solid var(--border-color);
          color: var(--text-primary);
          font-weight: 600;
          font-size: 0.9rem;
          text-decoration: none;
          transition: all 0.3s cubic-bezier(0.34, 1.56, 0.64, 1);
          cursor: pointer;
        }

        .btn-secondary:hover {
          transform: translateY(-3px);
          background: rgba(255,62,165,0.1);
          border-color: var(--accent-pink);
          box-shadow: 0 20px 60px rgba(255,62,165,0.1);
        }

        .social-links {
          display: flex;
          gap: 0.75rem;
        }

        .social-link {
          width: 44px;
          height: 44px;
          border-radius: 50%;
          background: var(--card-bg);
          border: 1px solid var(--border-color);
          display: inline-flex;
          align-items: center;
          justify-content: center;
          color: var(--text-secondary);
          text-decoration: none;
          font-size: 1.1rem;
          transition: all 0.3s cubic-bezier(0.34, 1.56, 0.64, 1);
        }

        .social-link:hover {
          background: var(--accent-pink);
          color: var(--bg-primary);
          transform: translateY(-3px);
          border-color: var(--accent-pink);
          box-shadow: 0 10px 30px rgba(255,62,165,0.2);
        }

        /* Profile Image */
        .profile-container {
          position: relative;
          display: flex;
          justify-content: center;
          align-items: center;
        }

        .profile-ring {
          position: relative;
          width: 380px;
          height: 380px;
          border-radius: 50%;
          background: conic-gradient(
            from 0deg,
            var(--accent-pink),
            var(--accent-secondary),
            var(--rose-gold),
            var(--accent-pink)
          );
          padding: 3px;
          animation: rotateRing 20s linear infinite;
        }

        @keyframes rotateRing {
          from { transform: rotate(0deg); }
          to { transform: rotate(360deg); }
        }

        .profile-inner {
          width: 100%;
          height: 100%;
          border-radius: 50%;
          overflow: hidden;
          background: var(--bg-primary);
          display: flex;
          align-items: center;
          justify-content: center;
        }

        .profile-image {
          width: 100%;
          height: 100%;
          object-fit: cover;
          border-radius: 50%;
        }

        /* Floating Labels Container */
        .floating-labels-container {
          position: absolute;
          inset: -80px;
          pointer-events: none;
        }

        /* Stats Section */
        .stats-container {
          display: grid;
          grid-template-columns: repeat(2, 1fr);
          gap: 1.5rem;
          max-width: 400px;
          margin: 0 auto;
        }

        .stat-card {
          background: var(--card-bg);
          border: 1px solid var(--border-color);
          border-radius: 16px;
          padding: 1.5rem;
          text-align: center;
          transition: all 0.4s cubic-bezier(0.34, 1.56, 0.64, 1);
          cursor: default;
        }

        .stat-card:hover {
          transform: translateY(-5px);
          border-color: var(--accent-pink);
          box-shadow: 0 20px 60px rgba(255,62,165,0.05);
        }

        .stat-number {
          font-family: 'IBM Plex Mono', monospace;
          font-size: 2.8rem;
          font-weight: 700;
          background: linear-gradient(135deg, var(--text-primary), var(--text-secondary));
          -webkit-background-clip: text;
          -webkit-text-fill-color: transparent;
          background-clip: text;
          line-height: 1;
        }

        .stat-label {
          color: var(--text-secondary);
          font-size: 0.85rem;
          margin-top: 0.25rem;
        }

        /* Tech Marquee */
        .tech-marquee {
          overflow: hidden;
          padding: 3rem 0;
          border-top: 1px solid var(--border-color);
          border-bottom: 1px solid var(--border-color);
          margin: 3rem 0;
        }

        .tech-marquee-track {
          display: flex;
          gap: 2rem;
          animation: marqueeScroll 30s linear infinite;
          width: max-content;
        }

        @keyframes marqueeScroll {
          0% { transform: translateX(0); }
          100% { transform: translateX(-50%); }
        }

        .tech-item {
          display: flex;
          align-items: center;
          gap: 0.75rem;
          background: var(--card-bg);
          border: 1px solid var(--border-color);
          border-radius: 50px;
          padding: 0.5rem 1.5rem;
          transition: all 0.3s cubic-bezier(0.34, 1.56, 0.64, 1);
          cursor: default;
          flex-shrink: 0;
          white-space: nowrap;
        }

        .tech-item:hover {
          transform: translateY(-3px) scale(1.05);
          border-color: var(--accent-pink);
          box-shadow: 0 10px 30px rgba(255,62,165,0.1);
        }

        .tech-icon {
          font-size: 1.2rem;
          color: var(--accent-pink);
        }

        .tech-name {
          font-size: 0.85rem;
          font-weight: 500;
          color: var(--text-secondary);
        }

        /* Project Cards */
        .project-card {
          background: var(--card-bg);
          border: 1px solid var(--border-color);
          border-radius: 20px;
          overflow: hidden;
          transition: all 0.5s cubic-bezier(0.34, 1.56, 0.64, 1);
          height: 100%;
          cursor: default;
          position: relative;
        }

        .project-card:hover {
          transform: translateY(-10px);
          border-color: var(--accent-pink);
          box-shadow: 0 30px 80px rgba(255,62,165,0.05);
        }

        .project-card::before {
          content: '';
          position: absolute;
          inset: 0;
          border-radius: 20px;
          padding: 1px;
          background: linear-gradient(135deg, transparent, var(--accent-pink), transparent);
          opacity: 0;
          transition: opacity 0.5s ease;
          pointer-events: none;
        }

        .project-card:hover::before {
          opacity: 0.3;
        }

        .project-card-image {
          width: 100%;
          height: 240px;
          object-fit: cover;
          transition: transform 0.6s cubic-bezier(0.34, 1.56, 0.64, 1);
        }

        .project-card:hover .project-card-image {
          transform: scale(1.05);
        }

        .project-card-body {
          padding: 1.5rem;
          position: relative;
        }

        .project-card-title {
          font-family: 'Space Grotesk', sans-serif;
          font-size: 1.1rem;
          font-weight: 700;
          color: var(--text-primary);
          margin-bottom: 0.25rem;
        }

        .project-card-desc {
          color: var(--text-secondary);
          font-size: 0.85rem;
          line-height: 1.6;
          margin-bottom: 1rem;
          display: -webkit-box;
          -webkit-line-clamp: 2;
          -webkit-box-orient: vertical;
          overflow: hidden;
        }

        .project-tech {
          display: flex;
          flex-wrap: wrap;
          gap: 0.4rem;
          margin-bottom: 1rem;
        }

        .project-tech-badge {
          background: var(--card-bg);
          border: 1px solid var(--border-color);
          color: var(--text-secondary);
          padding: 0.2rem 0.75rem;
          border-radius: 50px;
          font-size: 0.7rem;
          font-weight: 500;
          transition: all 0.3s ease;
        }

        .project-tech-badge:hover {
          border-color: var(--accent-pink);
          color: var(--text-primary);
        }

        .project-links {
          display: flex;
          gap: 0.75rem;
        }

        .project-link {
          display: inline-flex;
          align-items: center;
          gap: 0.4rem;
          padding: 0.3rem 1rem;
          border-radius: 50px;
          font-size: 0.8rem;
          font-weight: 500;
          text-decoration: none;
          transition: all 0.3s cubic-bezier(0.34, 1.56, 0.64, 1);
        }

        .project-link.primary {
          background: var(--accent-pink);
          color: var(--bg-primary);
        }

        .project-link.primary:hover {
          transform: translateY(-2px);
          box-shadow: 0 10px 30px rgba(255,62,165,0.3);
        }

        .project-link.secondary {
          border: 1px solid var(--border-color);
          color: var(--text-secondary);
        }

        .project-link.secondary:hover {
          border-color: var(--accent-pink);
          color: var(--text-primary);
          transform: translateY(-2px);
        }

        /* Section Styles */
        .section-title {
          font-family: 'Space Grotesk', sans-serif;
          font-size: 2.8rem;
          font-weight: 800;
          letter-spacing: -1px;
          margin-bottom: 0.5rem;
        }

        .section-title .gradient-text {
          background: linear-gradient(135deg, var(--accent-pink), var(--accent-secondary));
          -webkit-background-clip: text;
          -webkit-text-fill-color: transparent;
          background-clip: text;
        }

        .section-subtitle {
          color: var(--text-secondary);
          font-size: 1.05rem;
          margin-bottom: 2.5rem;
        }

        .section-divider {
          width: 60px;
          height: 3px;
          background: linear-gradient(90deg, var(--accent-pink), transparent);
          border-radius: 3px;
          margin: 1.5rem auto;
        }

        /* Skill Tags */
        .skill-tag {
          display: inline-flex;
          align-items: center;
          gap: 0.5rem;
          background: var(--card-bg);
          border: 1px solid var(--border-color);
          border-radius: 50px;
          padding: 0.5rem 1.5rem;
          color: var(--text-secondary);
          font-size: 0.85rem;
          font-weight: 500;
          margin: 0.3rem;
          transition: all 0.3s cubic-bezier(0.34, 1.56, 0.64, 1);
          cursor: default;
        }

        .skill-tag:hover {
          transform: translateY(-3px) scale(1.05);
          border-color: var(--accent-pink);
          color: var(--text-primary);
          box-shadow: 0 10px 30px rgba(255,62,165,0.05);
        }

        .skill-tag .tag-icon {
          color: var(--accent-pink);
        }

        /* Footer */
        .footer {
          padding: 2rem 0;
          border-top: 1px solid var(--border-color);
          margin-top: 4rem;
        }

        .footer-text {
          color: var(--text-secondary);
          font-size: 0.85rem;
          text-align: center;
        }

        .footer-text .heart {
          color: var(--accent-pink);
          display: inline-block;
        }

        /* Responsive */
        @media (max-width: 992px) {
          .hero-title {
            font-size: 3.5rem;
          }
          .profile-ring {
            width: 320px;
            height: 320px;
          }
          .floating-labels-container {
            inset: -60px;
          }
        }

        @media (max-width: 768px) {
          .main-content {
            padding-top: 100px;
          }
          .hero-title {
            font-size: 2.8rem;
          }
          .profile-ring {
            width: 280px;
            height: 280px;
            margin: 2rem auto;
          }
          .floating-labels-container {
            inset: -50px;
          }
          .hero-actions {
            flex-direction: column;
            align-items: stretch;
          }
          .btn-primary, .btn-secondary {
            justify-content: center;
          }
          .stats-container {
            grid-template-columns: repeat(2, 1fr);
            max-width: 100%;
          }
          .section-title {
            font-size: 2rem;
          }
          .floating-label {
            font-size: 0.6rem;
            padding: 4px 12px;
          }
        }

        @media (max-width: 576px) {
          .hero-title {
            font-size: 2.2rem;
          }
          .profile-ring {
            width: 220px;
            height: 220px;
          }
          .floating-labels-container {
            display: none;
          }
          .project-card-image {
            height: 180px;
          }
          .stat-number {
            font-size: 2rem;
          }
