                  key={i}
                  className="skill-tag"
                  initial={{ opacity: 0, scale: 0.8 }}
                  whileInView={{ opacity: 1, scale: 1 }}
                  viewport={{ once: true }}
                  transition={{ delay: i * 0.05, duration: 0.4 }}
                >
                  <i className="fas fa-check-circle tag-icon" />
                  {skill}
                </motion.span>
              ))}
            </div>
          </div>
        </section>

        {/* Recent Projects */}
        <section className="py-5">
          <div className="container">
            <motion.div
              initial={{ opacity: 0, y: 30 }}
              whileInView={{ opacity: 1, y: 0 }}
              viewport={{ once: true }}
              transition={{ duration: 0.6 }}
              className="text-center"
            >
              <h2 className="section-title">
                Recent <span className="gradient-text">Projects</span>
              </h2>
              <div className="section-divider" />
              <p className="section-subtitle">
                Some of the projects I've worked on
              </p>
            </motion.div>

            {recentProjects.length > 0 ? (
              <>
                <div className="row g-4">
                  {recentProjects.map((project, i) => {
                    const teknologiList = project.teknologi ? project.teknologi.split('|') : [];
                    return (
                      <motion.div
                        key={project.id}
                        className="col-md-4 col-sm-6 col-12"
                        initial={{ opacity: 0, y: 30 }}
                        whileInView={{ opacity: 1, y: 0 }}
                        viewport={{ once: true }}
                        transition={{ delay: i * 0.1, duration: 0.6 }}
                      >
                        <div className="project-card">
                          {project.gambar ? (
                            <img 
                              src={`/uploads/${project.gambar}`} 
                              alt={project.nama_project} 
                              className="project-card-image" 
                            />
                          ) : (
                            <div 
                              className="project-card-image d-flex align-items-center justify-content-center"
                              style={{ 
                                background: 'linear-gradient(135deg, var(--bg-secondary), var(--bg-primary))',
                              }}
                            >
                              <i className="fas fa-image" style={{ fontSize: '3rem', color: 'var(--text-secondary)' }} />
                            </div>
                          )}
                          <div className="project-card-body">
                            <h5 className="project-card-title">{project.nama_project}</h5>
                            <p className="project-card-desc">{project.deskripsi}</p>
                            <div className="project-tech">
                              {teknologiList.slice(0, 3).map((t, j) => (
                                <span className="project-tech-badge" key={j}>{t}</span>
                              ))}
