                                <span className="project-tech-badge">+{teknologiList.length - 3}</span>
                              )}
                            </div>
                            <div className="project-links">
                              {project.github && (
                                <a 
                                  href={project.github} 
                                  target="_blank" 
                                  rel="noreferrer"
                                  className="project-link secondary"
                                >
                                  <i className="fab fa-github me-1" />
                                  GitHub
                                </a>
                              )}
                              {project.demo && (
                                <a 
                                  href={project.demo} 
                                  target="_blank" 
                                  rel="noreferrer"
                                  className="project-link primary"
                                >
                                  <i className="fas fa-external-link-alt me-1" />
                                  Demo
                                </a>
                              )}
                            </div>
                          </div>
                        </div>
                      </motion.div>
                    );
                  })}
                </div>
                <div className="text-center mt-5">
                  <Link to="/project" className="btn-primary">
                    <span>
                      View All Projects
                      <i className="fas fa-arrow-right ms-2" />
                    </span>
                  </Link>
                </div>
              </>
            ) : (
              <div className="text-center py-5">
                <i className="fas fa-inbox" style={{ fontSize: '3rem', color: 'var(--text-secondary)' }} />
                <p className="text-secondary mt-3">No projects yet.</p>
              </div>
            )}
          </div>
        </section>
      </div>

      <footer className="footer">
        <div className="container">
          <div className="footer-text">
            <i className="fas fa-code me-2" style={{ color: 'var(--accent-pink)' }} />
            Built with <span className="heart"><i className="fas fa-heart" /></span> by Hagia Sofiana &bull; {new Date().getFullYear()}
          </div>
        </div>
      </footer>
    </>
  );
}
